#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, X, Y;
        scanf("%lld %lld %lld", &N, &X, &Y);
        long long rowcol = 2*(N-1);
        long long d1 = (X-1 < Y-1 ? X-1 : Y-1) + (N-X < N-Y ? N-X : N-Y);
        long long d2 = (X-1 < N-Y ? X-1 : N-Y) + (N-X < Y-1 ? N-X : Y-1);
        long long ans = rowcol + d1 + d2;
        printf("%lld\n", ans);
    }
    return 0;
}

